USE dikoin_manuales;

-- Taxonomia normalizada de productos DIKOIN basada en catalogo_productos_dikoin.xlsx
CREATE TABLE IF NOT EXISTS product_families (
  id BIGINT NOT NULL AUTO_INCREMENT,
  code VARCHAR(20) NOT NULL,
  name_es VARCHAR(160) NOT NULL,
  name_en VARCHAR(160) NULL,
  PRIMARY KEY (id),
  UNIQUE KEY uk_product_families_code (code)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS product_categories (
  id BIGINT NOT NULL AUTO_INCREMENT,
  code VARCHAR(20) NOT NULL,
  name_es VARCHAR(180) NOT NULL,
  name_en VARCHAR(180) NULL,
  PRIMARY KEY (id),
  UNIQUE KEY uk_product_categories_code (code)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

ALTER TABLE products ADD COLUMN IF NOT EXISTS name_es VARCHAR(160) NULL AFTER name;
ALTER TABLE products ADD COLUMN IF NOT EXISTS name_en VARCHAR(160) NULL AFTER name_es;
ALTER TABLE products ADD COLUMN IF NOT EXISTS family_code VARCHAR(20) NULL AFTER family;
ALTER TABLE products ADD COLUMN IF NOT EXISTS family_id BIGINT NULL AFTER family_code;
ALTER TABLE products ADD COLUMN IF NOT EXISTS category_codes VARCHAR(120) NULL AFTER category;
ALTER TABLE products ADD COLUMN IF NOT EXISTS description_es VARCHAR(600) NULL AFTER description;
ALTER TABLE products ADD COLUMN IF NOT EXISTS description_en VARCHAR(600) NULL AFTER description_es;

CREATE TABLE IF NOT EXISTS product_category_assignments (
  product_id BIGINT NOT NULL,
  category_id BIGINT NOT NULL,
  PRIMARY KEY (product_id, category_id),
  CONSTRAINT fk_product_category_assignments_product FOREIGN KEY (product_id) REFERENCES products(id) ON DELETE CASCADE,
  CONSTRAINT fk_product_category_assignments_category FOREIGN KEY (category_id) REFERENCES product_categories(id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

ON DUPLICATE KEY UPDATE name_es = VALUES(name_es), name_en = VALUES(name_en);

ON DUPLICATE KEY UPDATE name_es = VALUES(name_es), name_en = VALUES(name_en);

ON DUPLICATE KEY UPDATE name = VALUES(name), name_es = VALUES(name_es), family = VALUES(family), family_code = VALUES(family_code), category = VALUES(category), category_codes = VALUES(category_codes), description = VALUES(description), description_es = VALUES(description_es), active = TRUE, updated_at = COALESCE(NOW(), CURRENT_TIMESTAMP);

UPDATE products p JOIN product_families f ON f.code = p.family_code SET p.family_id = f.id WHERE p.family_code IS NOT NULL;

DELETE pca FROM product_category_assignments pca JOIN products p ON p.id = pca.product_id WHERE p.code IN ('FL 01.1', 'FL 01.2', 'FL 01.3', 'FL 01.4', 'FL 01.6', 'FL 01.7', 'FL 02.1', 'FL 04.1', 'FL 06.1', 'FL 06.2', 'FL 06.3', 'FL 09.2', 'FL 10.1', 'FL 10.2', 'FL 11.1', 'FL 12.1', 'FL 12.2', 'FL 13.1', 'FL 14.1', 'FL 14.2', 'FL 14.3', 'FL 15.1', 'FL 15.2', 'FL 17.1', 'FL 17.2', 'FL 18.1', 'FL 18.2', 'FL 23.1', 'FL 27.2', 'FL 28.1', 'FL 29.1', 'FL 29.3', 'FL 30.1', 'FLB 03.1', 'FLB 03.2', 'FLB 06.2', 'FLB 10.1', 'FLB 11.1', 'FLB 13.1', 'FLB 14.2', 'FLB 23.1', 'FL 03.1', 'FL 03.1i', 'FL 03.2', 'FL 07.1', 'FL 07.2', 'MH 01.1', 'TH 01.1', 'TH 01.2', 'TH 01.4', 'TH 03.1', 'TH 03.2', 'TH 03.4', 'TH 04.1', 'TH 04.2', 'TH 04.4', 'FL 05.1', 'FL 05.3', 'FL 05.4', 'FL 05.5', 'FL 09.1', 'FL 16.1', 'FL 16.2', 'FLB 09.2', 'HD 06.1', 'HD 10.1', 'HD 11.1', 'TA 02.2', 'TA 03.2', 'EN 01.4', 'EN 01.4PC', 'EN 01.5', 'EN 01.6', 'EN 01.7', 'EN 04.1', 'EN 04.2', 'EN 04.3', 'EN 04.4', 'EN 04.5', 'EN 05.1', 'AC 03.1', 'IT 03.2', 'RF 01.1', 'TC 01.1', 'TC 01.2', 'TC 01.3', 'TC 01.4', 'TC 01.5', 'TC 02.1', 'TC 02.2', 'TC 02.3', 'TC 02.4', 'TC 02.5', 'TC 02.6', 'TC 06.1', 'TC 07.1', 'TD 01.1', 'TD 01.2', 'IQ 01.5', 'IQ 02.1', 'ST 01.1', 'ST 01.2', 'ST 03.1', 'ST.Z.01', 'ST.Z.02', 'MM01', 'MM02', 'MM03', 'MM04', 'MM05', 'MM06', 'MM07', 'MM08', 'MM09', 'MM10', 'MM11');

